script:
// gh#150 Part 1 — Custom GSP Health card. Renders inside the shadow
// DOM Frappe wraps Custom HTML Blocks with; scope all lookups to
// `root_element` (the shadow root).
const root = root_element.querySelector('.ecs-gsp-health');
if (root) {
  frappe.call({
    method: 'ecommerce_super.easyecom.api.gsp_health.get_metrics',
    callback: function(r){
      const m = (r && r.message) || {};
      const asOfEl = root.querySelector('[data-bind=as_of]');
      if (asOfEl && m.as_of) asOfEl.textContent = 'as of ' + frappe.datetime.prettyDate(m.as_of);

      const setValue = (key, textFn, tileClass) => {
        const el = root.querySelector('[data-bind=' + key + ']');
        if (!el) return;
        el.textContent = textFn(m[key]);
        const tile = el.closest('.ecs-gsp-tile');
        if (tile && tileClass) tile.classList.add(tileClass);
      };

      setValue('last_success_at', v => v ? frappe.datetime.prettyDate(v) : '—');
      setValue(
        'inbound_today',
        v => (v == null ? '—' : String(v)),
        (m.inbound_today > 0) ? 'ecs-gsp-tile-ok' : ''
      );
      setValue(
        'failed_inbound_today',
        v => (v == null ? '—' : String(v)),
        (m.failed_inbound_today > 0) ? 'ecs-gsp-tile-warn' : 'ecs-gsp-tile-ok'
      );
      setValue(
        'stuck_orders_6h',
        v => (v == null ? '—' : String(v)),
        (m.stuck_orders_6h > 0) ? 'ecs-gsp-tile-warn' : 'ecs-gsp-tile-ok'
      );

      // Top failure reasons — render as a compact table
      const reasonsEl = root.querySelector('[data-bind=top_failure_reasons]');
      if (reasonsEl) {
        const reasons = m.top_failure_reasons || [];
        if (reasons.length === 0) {
          reasonsEl.innerHTML = '<div class="ecs-gsp-empty">No failures in the last 24h.</div>';
        } else {
          const rows = reasons.map(r =>
            `<div class="ecs-gsp-reason-row">
               <span class="ecs-gsp-reason-count">${r.count}</span>
               <span class="ecs-gsp-reason-text">${frappe.utils.escape_html(r.reason)}</span>
             </div>`
          ).join('');
          reasonsEl.innerHTML = rows;
        }
      }
    }
  });
}

style:
.ecs-gsp-health { background: var(--bg-color, #fff); border: 1px solid var(--border-color, #e0e0e0); border-radius: 8px; padding: 16px; }
.ecs-gsp-title { font-size: 14px; font-weight: 600; color: #111827; margin-bottom: 12px; }
.ecs-gsp-asof { font-size: 11px; font-weight: 400; color: #9ca3af; margin-left: 8px; }
.ecs-gsp-tiles { display: grid; grid-template-columns: repeat(auto-fit, minmax(180px, 1fr)); gap: 12px; margin-bottom: 16px; }
.ecs-gsp-tile { background: #f9fafb; border-radius: 6px; padding: 12px 14px; border-left: 3px solid #e5e7eb; }
.ecs-gsp-tile-ok { border-left-color: #059669; }
.ecs-gsp-tile-warn { border-left-color: #d97706; background: #fffbeb; }
.ecs-gsp-label { font-size: 11px; text-transform: uppercase; color: #6b7280; letter-spacing: 0.3px; margin-bottom: 4px; }
.ecs-gsp-value { font-size: 16px; font-weight: 600; color: #111827; }
.ecs-gsp-reasons { padding-top: 8px; border-top: 1px solid #f3f4f6; }
.ecs-gsp-reason-row { display: flex; gap: 12px; padding: 6px 0; font-size: 12px; color: #374151; }
.ecs-gsp-reason-count { min-width: 32px; font-weight: 700; color: #dc2626; }
.ecs-gsp-reason-text { flex: 1; font-family: 'SF Mono', 'Monaco', monospace; font-size: 11px; color: #4b5563; }
.ecs-gsp-empty { font-size: 12px; color: #9ca3af; padding: 8px 0; font-style: italic; }
